div.p:
RequestVoteArgs {
Term: T+1
CandidateId: "candidate"
LastLogIndex: N
LastLogTerm: T_N
}

if candidateLastTerm > myLastTerm:
upToDate = true
elif candidateLastTerm == myLastTerm:
upToDate = candidateLastIndex >= myLastIndex
else:
upToDate = false

votesReceived = 1  // Self-vote
votesNeeded = (N+1)/2 + 1  // Majority
for each VoteReply:
if reply.Term > currentTerm:
stepDown()
return
if reply.VoteGranted:
votesReceived++
if votesReceived >= votesNeeded:
becomeLeader()
